$ErrorActionPreference='Stop';$script=Join-Path $PSScriptRoot 'get-task-budget-advice.ps1';$low=(& $script -Tier T0 -Json|Out-String)|ConvertFrom-Json;$high=(& $script -Tier T4 -ChangedFiles 10 -HasExternalState -Json|Out-String)|ConvertFrom-Json;if($low.estimatedMinutes -ge $high.estimatedMinutes -or $high.confidence -ne 'HEURISTIC' -or $high.automaticModelChange){throw 'Budget advice contract failed.'};Write-Host 'Task budget advice tests passed'
